#include <stdio.h>
#include <stdlib.h>

struct Node {
  int data;
  struct Node* next;
};

void append(struct Node** head, int data) {
  struct Node* new_node = (struct Node*)malloc(sizeof(struct Node));
  new_node->data = data;
  new_node->next = NULL;

  if (*head == NULL) {
    *head = new_node;
    return;
  }

  struct Node* current = *head;
  while (current->next != NULL) {
    current = current->next;
  }
  current->next = new_node;
}

void print_list(struct Node* head) {
  struct Node* current = head;
  while (current != NULL) {
    printf("%d ", current->data);
    current = current->next;
  }
  printf("\n");
}

int main() {
  struct Node* head = NULL;
  append(&head, 10);
  append(&head, 20);
  append(&head, 30);
  printf("Bağlı siyahı: ");
  print_list(head);
  return 0;
}
// Output:
// Bağlı siyahı: 10 20 30

