struct Node {
  int data;
  struct Node* next;
};

void append(struct Node** head, int data) {
  struct Node* new_node = (struct Node*)malloc(sizeof(struct Node));
  new_node->data = data;
  new_node->next = NULL;

  if (*head == NULL) {
    *head = new_node;
    return;
  }

  struct Node* current = *head;
  while (current->next != NULL) {
    current = current->next;
  }
  current->next = new_node;
}

void delete_node(struct Node** head, int key) {
  struct Node* temp = *head;
  struct Node* prev = NULL;

  if (temp != NULL && temp->data == key) {
    *head = temp->next;
    free(temp);
    return;
  }

  while (temp != NULL && temp->data != key) {
    prev = temp;
    temp = temp->next;
  }

  if (temp == NULL) return;

  prev->next = temp->next;
  free(temp);
}

void print_list(struct Node* head) {
  struct Node* current = head;
  while (current != NULL) {
    printf("%d ", current->data);
    current = current->next;
  }
  printf("\n");
}

int main() {
  struct Node* head = NULL;
  append(&head, 10);
  append(&head, 20);
  append(&head, 30);
  printf("Əvvəlki siyahı: ");
  print_list(head);
  delete_node(&head, 20);
  printf("20 silindikdən sonra: ");
  print_list(head);
  return 0;
}
// Output:
// Əvvəlki siyahı: 10 20 30
// 20 silindikdən sonra: 10 30

